/**********************************************************************
 *
 * Memory subsystem.
 *
 */

static void
MFixLine(p, y, mc)
struct win *p;
int y;
struct mchar *mc;
{
  struct mline *ml = &p->w_mlines[y];
  if (mc->attr && ml->attr == null)
    {
      if ((ml->attr = (unsigned char *)calloc(p->w_width + 1, 1)) == 0)
	{
	  ml->attr = null;
	  mc->attr = p->w_rend.attr = 0;
	  WMsg(p, 0, "Warning: no space for attr - turned off");
	}
    }
#ifdef FONT
  if (mc->font && ml->font == null)
    {
      if ((ml->font = (unsigned char *)calloc(p->w_width + 1, 1)) == 0)
	{
	  ml->font = null;
	  p->w_FontL = p->w_charsets[p->w_ss ? p->w_ss : p->w_Charset] = 0;
	  p->w_FontR = p->w_charsets[p->w_ss ? p->w_ss : p->w_CharsetR] = 0;
	  mc->font = mc->fontx = p->w_rend.font  = 0;
	  WMsg(p, 0, "Warning: no space for font - turned off");
	}
    }
  if (mc->fontx && ml->fontx == null)
    {
      if ((ml->fontx = (unsigned char *)calloc(p->w_width + 1, 1)) == 0)
	{
	  ml->fontx = null;
	  mc->fontx = 0;
	}
    }
#endif
#ifdef COLOR
  if (mc->color && ml->color == null)
    {
      if ((ml->color = (unsigned char *)calloc(p->w_width + 1, 1)) == 0)
	{
	  ml->color = null;
	  mc->color = p->w_rend.color = 0;
	  WMsg(p, 0, "Warning: no space for color - turned off");
	}
    }
# ifdef COLORS256
  if (mc->colorx && ml->colorx == null)
    {
      if ((ml->colorx = (unsigned char *)calloc(p->w_width + 1, 1)) == 0)
	{
	  ml->colorx = null;
	  mc->colorx = p->w_rend.colorx = 0;
	  WMsg(p, 0, "Warning: no space for extended colors - turned off");
	}
    }
# endif
#endif
}

/*****************************************************************/

#ifdef DW_CHARS
# define MKillDwRight(p, ml, x)					\
  if (dw_right(ml, x, p->w_encoding))				\
    {								\
      if (x > 0)						\
	copy_mchar2mline(&mchar_blank, ml, x - 1);		\
      copy_mchar2mline(&mchar_blank, ml, x);			\
    }

# define MKillDwLeft(p, ml, x)					\
  if (dw_left(ml, x, p->w_encoding))				\
    {								\
      copy_mchar2mline(&mchar_blank, ml, x);			\
      copy_mchar2mline(&mchar_blank, ml, x + 1);		\
    }
#else
# define MKillDwRight(p, ml, x) ;
# define MKillDwLeft(p, ml, x) ;
#endif

static void
MScrollH(p, n, y, xs, xe, bce)
struct win *p;
int n, y, xs, xe, bce;
{
  struct mline *ml;

  if (n == 0)
    return;
  ml = &p->w_mlines[y];
  MKillDwRight(p, ml, xs);
  MKillDwLeft(p, ml, xe);
  if (n > 0)
    {
      if (xe - xs + 1 > n)
	{
	  MKillDwRight(p, ml, xs + n);
	  bcopy_mline(ml, xs + n, xs, xe + 1 - xs - n);
	}
      else
	n = xe - xs + 1;
      clear_mline(ml, xe + 1 - n, n);
#ifdef COLOR
      if (bce)
        MBceLine(p, y, xe + 1 - n, n, bce);
#endif
    }
  else
    {
      n = -n;
      if (xe - xs + 1 > n)
	{
	  MKillDwLeft(p, ml, xe - n);
	  bcopy_mline(ml, xs, xs + n, xe + 1 - xs - n);
	}
      else
	n = xe - xs + 1;
      clear_mline(ml, xs, n);
#ifdef COLOR
      if (bce)
        MBceLine(p, y, xs, n, bce);
#endif
    }
}

static void
MScrollV(p, n, ys, ye, bce)
struct win *p;
int n, ys, ye, bce;
{
  int i, cnt1, cnt2;
  struct mline tmp[256];
  struct mline *ml;

  if (n == 0)
    return;
  if (n > 0)
    {
      if (ye - ys + 1 < n)
	n = ye - ys + 1;
      if (n > 256)
	{
	  MScrollV(p, n - 256, ys, ye, bce);
	  n = 256;
	}
#ifdef COPY_PASTE
      if (compacthist)
	{
	  ye = MFindUsedLine(p, ye, ys);
	  if (ye - ys + 1 < n)
	    n = ye - ys + 1;
	  if (n <= 0)
	    return;
	}
#endif
      /* Clear lines */
      ml = p->w_mlines + ys;
      for (i = ys; i < ys + n; i++, ml++)
	{
#ifdef COPY_PASTE
	  if (ys == p->w_top)
	    WAddLineToHist(p, ml);
#endif
	  if (ml->attr != null)
	    free(ml->attr);
	  ml->attr = null;
#ifdef FONT
	  if (ml->font != null)
	    free(ml->font);
	  ml->font = null;
	  if (ml->fontx != null)
	    free(ml->fontx);
	  ml->fontx = null;
#endif
#ifdef COLOR
	  if (ml->color != null)
	    free(ml->color);
	  ml->color = null;
# ifdef COLORS256
	  if (ml->colorx != null)
	    free(ml->colorx);
	  ml->colorx = null;
# endif
#endif
	  bclear((char *)ml->image, p->w_width + 1);
#ifdef COLOR
	  if (bce)
	    MBceLine(p, i, 0, p->w_width, bce);
#endif
	}
      /* switch 'em over */
      cnt1 = n * sizeof(struct mline);
      cnt2 = (ye - ys + 1 - n) * sizeof(struct mline);
      if (cnt1 && cnt2)
	Scroll((char *)(p->w_mlines + ys), cnt1, cnt2, (char *)tmp);
    }
  else
    {
      n = -n;
      if (ye - ys + 1 < n)
	n = ye - ys + 1;
      if (n > 256)
	{
	  MScrollV(p, - (n - 256), ys, ye, bce);
	  n = 256;
	}

      ml = p->w_mlines + ye;
      /* Clear lines */
      for (i = ye; i > ye - n; i--, ml--)
	{
	  if (ml->attr != null)
	    free(ml->attr);
	  ml->attr = null;
#ifdef FONT
	  if (ml->font != null)
	    free(ml->font);
	  ml->font = null;
	  if (ml->fontx != null)
	    free(ml->fontx);
	  ml->fontx = null;
#endif
#ifdef COLOR
	  if (ml->color != null)
	    free(ml->color);
	  ml->color = null;
# ifdef COLORS256
	  if (ml->colorx != null)
	    free(ml->colorx);
	  ml->colorx = null;
# endif
#endif
	  bclear((char *)ml->image, p->w_width + 1);
#ifdef COLOR
	  if (bce)
	    MBceLine(p, i, 0, p->w_width, bce);
#endif
	}
      cnt1 = n * sizeof(struct mline);
      cnt2 = (ye - ys + 1 - n) * sizeof(struct mline);
      if (cnt1 && cnt2)
	Scroll((char *)(p->w_mlines + ys), cnt2, cnt1, (char *)tmp);
    }
}

static void
Scroll(cp, cnt1, cnt2, tmp)
char *cp, *tmp;
int cnt1, cnt2;
{
  if (!cnt1 || !cnt2)
    return;
  if (cnt1 <= cnt2)
    {
      bcopy(cp, tmp, cnt1);
      bcopy(cp + cnt1, cp, cnt2);
      bcopy(tmp, cp + cnt2, cnt1);
    }
  else
    {
      bcopy(cp + cnt1, tmp, cnt2);
      bcopy(cp, cp + cnt2, cnt1);
      bcopy(tmp, cp, cnt2);
    }
}

static void
MClearArea(p, xs, ys, xe, ye, bce)
struct win *p;
int xs, ys, xe, ye, bce;
{
  int n, y;
  int xxe;
  struct mline *ml;

  /* Check for zero-height window */
  if (ys < 0 || ye < ys)
    return;

  /* check for magic margin condition */
  if (xs >= p->w_width)
    xs = p->w_width - 1;
  if (xe >= p->w_width)
    xe = p->w_width - 1;

  MKillDwRight(p, p->w_mlines + ys, xs);
  MKillDwLeft(p, p->w_mlines + ye, xe);

  ml = p->w_mlines + ys;
  for (y = ys; y <= ye; y++, ml++)
    {
      xxe = (y == ye) ? xe : p->w_width - 1;
      n = xxe - xs + 1;
      if (n > 0)
	clear_mline(ml, xs, n);
#ifdef COLOR
      if (n > 0 && bce)
	MBceLine(p, y, xs, xs + n - 1, bce);
#endif
      xs = 0;
    }
}

static void
MInsChar(p, c, x, y)
struct win *p;
struct mchar *c;
int x, y;
{
  int n;
  struct mline *ml;

  ASSERT(x >= 0 && x < p->w_width);
  MFixLine(p, y, c);
  ml = p->w_mlines + y;
  n = p->w_width - x - 1;
  MKillDwRight(p, ml, x);
  if (n > 0)
    {
      MKillDwRight(p, ml, p->w_width - 1);
      bcopy_mline(ml, x, x + 1, n);
    }
  copy_mchar2mline(c, ml, x);
#ifdef DW_CHARS
  if (c->mbcs)
    {
      if (--n > 0)
        {
          MKillDwRight(p, ml, p->w_width - 1);
	  bcopy_mline(ml, x + 1, x + 2, n);
	}
      copy_mchar2mline(c, ml, x + 1);
      ml->image[x + 1] = c->mbcs;
# ifdef UTF8
      if (p->w_encoding != UTF8)
	ml->font[x + 1] |= 0x80;
      else if (p->w_encoding == UTF8 && c->mbcs)
	{
	  ml->font[x + 1] = c->mbcs;
	  ml->fontx[x + 1] = 0;
	}
# else
      ml->font[x + 1] |= 0x80;
# endif
    }
#endif
}

static void
MPutChar(p, c, x, y)
struct win *p;
struct mchar *c;
int x, y;
{
  struct mline *ml;

  MFixLine(p, y, c);
  ml = &p->w_mlines[y];
  MKillDwRight(p, ml, x);
  MKillDwLeft(p, ml, x);
  copy_mchar2mline(c, ml, x);
#ifdef DW_CHARS
  if (c->mbcs)
    {
      MKillDwLeft(p, ml, x + 1);
      copy_mchar2mline(c, ml, x + 1);
      ml->image[x + 1] = c->mbcs;
# ifdef UTF8
      if (p->w_encoding != UTF8)
	ml->font[x + 1] |= 0x80;
      else if (p->w_encoding == UTF8 && c->mbcs)
	{
	  ml->font[x + 1] = c->mbcs;
	  ml->fontx[x + 1] = 0;
	}
# else
      ml->font[x + 1] |= 0x80;
# endif
    }
#endif
}


static void
MWrapChar(p, c, y, top, bot, ins)
struct win *p;
struct mchar *c;
int y, top, bot;
int ins;
{
  struct mline *ml;
  int bce;

#ifdef COLOR
  bce = rend_getbg(c);
#else
  bce = 0;
#endif
  MFixLine(p, y, c);
  ml = &p->w_mlines[y];
  copy_mchar2mline(&mchar_null, ml, p->w_width);
  if (y == bot)
    MScrollV(p, 1, top, bot, bce);
  else if (y < p->w_height - 1)
    y++;
  if (ins)
    MInsChar(p, c, 0, y);
  else
    MPutChar(p, c, 0, y);
}

static void
MPutStr(p, s, n, r, x, y)
struct win *p;
char *s;
int n;
struct mchar *r;
int x, y;
{
  struct mline *ml;
  int i;
  unsigned char *b;

  if (n <= 0)
    return;
  MFixLine(p, y, r);
  ml = &p->w_mlines[y];
  MKillDwRight(p, ml, x);
  MKillDwLeft(p, ml, x + n - 1);
  bcopy(s, (char *)ml->image + x, n);
  if (ml->attr != null)
    {
      b = ml->attr + x;
      for (i = n; i-- > 0;)
	*b++ = r->attr;
    }
#ifdef FONT
  if (ml->font != null)
    {
      b = ml->font + x;
      for (i = n; i-- > 0;)
	*b++ = r->font;
    }
  if (ml->fontx != null)
    {
      b = ml->fontx + x;
      for (i = n; i-- > 0;)
	*b++ = r->fontx;
    }
#endif
#ifdef COLOR
  if (ml->color != null)
    {
      b = ml->color + x;
      for (i = n; i-- > 0;)
	*b++ = r->color;
    }
# ifdef COLORS256
  if (ml->colorx != null)
    {
      b = ml->colorx + x;
      for (i = n; i-- > 0;)
	*b++ = r->colorx;
    }
# endif
#endif
}

#ifdef COLOR
static void
MBceLine(p, y, xs, xe, bce)
struct win *p;
int y, xs, xe, bce;
{
  struct mchar mc;
  struct mline *ml;
  int x;

  mc = mchar_null;
  rend_setbg(&mc, bce);
  MFixLine(p, y, &mc);
  ml = p->w_mlines + y;
# ifdef COLORS16
  if (mc.attr)
    for (x = xs; x <= xe; x++)
      ml->attr[x] = mc.attr;
# endif
  if (mc.color)
    for (x = xs; x <= xe; x++)
      ml->color[x] = mc.color;
# ifdef COLORS256
  if (mc.colorx)
    for (x = xs; x <= xe; x++)
      ml->colorx[x] = mc.colorx;
# endif
}
#endif


#ifdef COPY_PASTE
static void
WAddLineToHist(wp, ml)
struct win *wp;
struct mline *ml;
{
  register unsigned char *q, *o;
  struct mline *hml;

  if (wp->w_histheight == 0)
    return;
  hml = &wp->w_hlines[wp->w_histidx];
  q = ml->image; ml->image = hml->image; hml->image = q;

  q = ml->attr; o = hml->attr; hml->attr = q; ml->attr = null;
  if (o != null)
    free(o);
 
#ifdef FONT
  q = ml->font; o = hml->font; hml->font = q; ml->font = null;
  if (o != null)
    free(o);
  q = ml->fontx; o = hml->fontx; hml->fontx = q; ml->fontx = null;
  if (o != null)
    free(o);
#endif

#ifdef COLOR
  q = ml->color; o = hml->color; hml->color = q; ml->color = null;
  if (o != null)
    free(o);
# ifdef COLORS256
  q = ml->colorx; o = hml->colorx; hml->colorx = q; ml->colorx = null;
  if (o != null)
    free(o);
# endif
#endif

  if (++wp->w_histidx >= wp->w_histheight)
    wp->w_histidx = 0;
  if (wp->w_scrollback_height < wp->w_histheight)
    ++wp->w_scrollback_height;
}
#endif

int
MFindUsedLine(p, ye, ys)
struct win *p;
int ys, ye;
{
  int y;
  struct mline *ml = p->w_mlines + ye;

  debug2("MFindUsedLine: %d %d\n", ye, ys);
  for (y = ye; y >= ys; y--, ml--)
    {
      if (bcmp((char*)ml->image, blank, p->w_width))
	break;
      if (ml->attr != null && bcmp((char*)ml->attr, null, p->w_width))
	break;
#ifdef COLOR
      if (ml->color != null && bcmp((char*)ml->color, null, p->w_width))
	break;
# ifdef COLORS256
      if (ml->colorx != null && bcmp((char*)ml->colorx, null, p->w_width))
	break;
# endif
#endif
#ifdef UTF8
      if (p->w_encoding == UTF8)
	{
	  if (ml->font != null && bcmp((char*)ml->font, null, p->w_width))
	    break;
	  if (ml->fontx != null && bcmp((char*)ml->fontx, null, p->w_width))
	    break;
	}
#endif
    }
  debug1("MFindUsedLine returning  %d\n", y);
  return y;
}


